import http from 'http';

function makeRequest(options: any, body: string | null = null): Promise<{status: number, body: string}> {
  return new Promise((resolve, reject) => {
    const req = http.request(options, (res) => {
      let data = '';
      res.on('data', (chunk: Buffer) => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode || 0, body: data }));
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

async function main() {
  const auth = Buffer.from('admin:admin').toString('base64');

  // Check Documents folder
  const checkResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents',
    method: 'PROPFIND',
    headers: {
      'Authorization': `Basic ${auth}`,
      'Depth': '0'
    }
  });
  console.log('Documents check status:', checkResult.status);

  // Create ProjectReports folder
  const createResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents/ProjectReports',
    method: 'MKCOL',
    headers: {
      'Authorization': `Basic ${auth}`
    }
  });
  console.log('Create folder status:', createResult.status);
  console.log('Create folder response:', createResult.body);

  // Verify
  const verifyResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents',
    method: 'PROPFIND',
    headers: {
      'Authorization': `Basic ${auth}`,
      'Depth': '1'
    }
  });
  console.log('Verify status:', verifyResult.status);
  console.log('Contents:', verifyResult.body);
}

main().catch(console.error);

#!/bin/bash
curl -u theagentcompany:theagentcompany -o /tmp/command.txt http://the-agent-company.com:8092/remote.php/dav/files/theagentcompany/Documents/command.txt
